  # Returns the named inline SVG, decorated with an `icon` class (spinner also
  # spins) and aria-hidden. Raises for an unknown name (fail fast).
  def icon(name, **opts)
    key = name.to_sym
    svg = ICONS.fetch(key)
    extra = opts.delete(:class)
    classes = [ "icon", ("icon--spin" if key == :spinner), extra ].compact.join(" ")
    tag.span(svg.html_safe, class: classes, "aria-hidden": "true", **opts)
  end
end
